use std::io::{self, BufRead};

fn main() {
    let stdin = io::stdin();
    let mut table = String::new();
    let mut hand = String::new();

    stdin.lock().read_line(&mut table).unwrap();
    stdin.lock().read_line(&mut hand).unwrap();

    let table = table.as_bytes();
    let hand = hand.trim().split(" ");
    for card in hand {
        let card = card.as_bytes();
        if card[0] == table[0] || card[1] == table[1] {
            println!("YES");
            return;
        }
    }
    println!("NO");
}
